        raise ValueError("Amount must be positive")
    print("Processing...")

try:
    process_payment(-50)
except ValueError as e:
    print(f"Caught: {e}")

challenge.solution:
def check_config(cfg):
    if 'host' not in cfg:
        raise KeyError('Missing host')
    if not isinstance(cfg['port'], int):
        raise TypeError('Port must be int')
    if cfg['port'] < 1024:
        raise ValueError('Port must be >= 1024')
    return True

check_config({'host': 'localhost', 'port': 8080})
